import { Bar } from 'react-chartjs-2';
const Barchart1 = (props) => {

    // const keywords = props.keywords;
    // const country = props.country;



    return (
        <div>
            <Bar
                data={{
                    labels: ['Positive', 'Negative'],
                    datasets: [
                        {
                            label: 'Sentiment Review',
                            data: this.state.predictions,
                            backgroundColor: [
                                'rgba(255, 99, 132, 0.2)',
                                'rgba(54, 162, 235, 0.2)',

                            ],
                            borderColor: [
                                'rgba(255, 99, 132, 0.2)',
                                'rgba(54, 162, 235, 0.2)',
                            ],
                            borderWidth: 1,
                        }
                    ]
                }}
                height={400}
                width={600}
                options={{
                    maintainAspectRatio: false,
                    scales: {
                        yAxes: [
                            {
                                ticks: {
                                    beginAtZero: true
                                }
                            }
                        ]
                    }
                }}
            />
            <div>Average Price: {this.state.avgPrice}</div>
            <div>Average Rating: {this.state.avgRating}</div>
            <div>Sold Units: {this.state.soldUnits}</div>
        </div>
    );
}

export default Barchart1;
